import pandas as pd
from statsmodels.tsa.stattools import adfuller

def task_func(df: pd.DataFrame, column_a: str, column_b: str, column_c: str):
    # Filter the data based on the provided conditions
    filtered_df = df[(df[column_b] > 50) & (df[column_c] == 900)]

    # Ensure there are non-empty and non-constant values in column_a after filtering
    if len(filtered_df[column_a]) > 1 and not filtered_df[column_a].isna().all() and not filtered_df[column_a].duplicated().sum() < len(filtered_df):
        # Perform the Augmented Dickey-Fuller test on the filtered data in column_a
        result = adfuller(filtered_df[column_a])
        p_value = result[1]

        # Check if the data is stationary based on the p-value
        is_stationary = p_value < 0.05

        return tuple(is_stationary, p_value)
    else:
        return tuple(False, None)
